function ensureModalRoot() {
  let root = document.getElementById('meyos-modal');
  if (root) return root;
  root = document.createElement('div');
  root.id = 'meyos-modal';
  root.className = 'modal';
  root.setAttribute('aria-hidden', 'true');
  root.innerHTML = `
    <div class="modal__dialog" role="dialog" aria-modal="true" tabindex="-1">
      <button class="modal__close" aria-label="Закрыть" data-modal-close>
        <span class="material-symbols-outlined">close</span>
      </button>
      <div class="modal__content"></div>
    </div>
  `;
  document.body.appendChild(root);
  const shut = () => closeModal();
  root.addEventListener('click', (e) => { if (e.target === root) shut(); });
  root.querySelector('[data-modal-close]').addEventListener('click', shut);
  document.addEventListener('keydown', (e) => { if (e.key === 'Escape') shut(); });
  return root;
}
function openModal(html, opts = {}) {
  const root = ensureModalRoot();
  const content = root.querySelector('.modal__content');
  if (opts.success) root.classList.add('modal--success'); else root.classList.remove('modal--success');
  content.innerHTML = html;
  requestAnimationFrame(() => {
    root.classList.add('is-open');
    root.setAttribute('aria-hidden', 'false');
    document.body.style.overflow = 'hidden';
  });
}
function closeModal() {
  const root = document.getElementById('meyos-modal');
  if (!root) return;
  root.classList.remove('is-open');
  root.setAttribute('aria-hidden', 'true');
  document.body.style.overflow = '';
}
function initMobileMenu() {
  const burger = document.querySelector('[data-burger]');
  const menu = document.querySelector('[data-mobile-menu]');
  const close = document.querySelector('[data-mobile-close]');
  if (!burger || !menu) return;
  const open = () => { menu.classList.add('is-open'); document.body.style.overflow = 'hidden'; };
  const shut = () => { menu.classList.remove('is-open'); document.body.style.overflow = ''; };
  burger.addEventListener('click', open);
  close?.addEventListener('click', shut);
  menu.querySelectorAll('a').forEach(a => a.addEventListener('click', shut));
}
function initForms() {
  document.querySelectorAll('form[data-join-form]').forEach(form => {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const btn = form.querySelector('button[type="submit"]');
      const orig = btn.textContent;
      btn.textContent = 'Отправляем…';
      btn.disabled = true;
      setTimeout(() => {
        form.reset();
        btn.textContent = orig;
        btn.disabled = false;
        openModal(`
          <div class="modal__success-icon">
            <span class="material-symbols-outlined">check_circle</span>
          </div>
          <h2 style="font-size:1.6rem; margin:0 0 .75rem;">Заявка принята</h2>
          <p class="text-mut" style="font-size:1rem; line-height:1.6; margin:0 0 1.5rem;">
            Спасибо! Менеджер MEYOS свяжется с вами в течение одного рабочего дня — для уточнения деталей и следующих шагов.
          </p>
          <div style="display:flex; gap:.75rem; justify-content:center; flex-wrap:wrap;">
            <button class="btn btn-primary" data-modal-close>Хорошо</button>
            <a href="programs.html" class="btn btn-ghost">Посмотреть программы</a>
          </div>
        `, { success: true });
        document.querySelectorAll('[data-modal-close]').forEach(b => b.addEventListener('click', closeModal));
      }, 900);
    });
  });
}
function initLang() {
  document.querySelectorAll('.lang button, .mobile-lang button').forEach(btn => {
    btn.addEventListener('click', () => {
      const group = btn.parentElement;
      group.querySelectorAll('button').forEach(b => b.classList.remove('is-active'));
      btn.classList.add('is-active');
      const lang = btn.textContent.trim().toLowerCase();
      document.querySelectorAll('.lang, .mobile-lang').forEach(g => {
        g.querySelectorAll('button').forEach(b => {
          b.classList.toggle('is-active', b.textContent.trim().toLowerCase() === lang);
        });
      });
      if (window.MEYOS_I18N) window.MEYOS_I18N.apply(lang);
    });
  });
}
function initCardFilter(filterSel, cardSel) {
  document.querySelectorAll(filterSel).forEach(group => {
    const chips = group.querySelectorAll('.filter-chip');
    const cards = document.querySelectorAll(cardSel);
    if (!chips.length || !cards.length) return;
    chips.forEach(chip => {
      chip.addEventListener('click', () => {
        chips.forEach(c => c.classList.remove('is-active'));
        chip.classList.add('is-active');
        const cat = chip.dataset.filter;
        cards.forEach(card => {
          const match = cat === 'all' || card.dataset.category === cat;
          card.classList.toggle('is-hidden', !match);
        });
      });
    });
  });
}
function initPartnersFilter() {
  initCardFilter('[data-partners-filter]', '[data-partner-card]');
}
function initNewsFilter() {
  initCardFilter('[data-news-filter]', '[data-news-card]');
}
