function attachFormHandler(form) {
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const btn = form.querySelector('button[type="submit"]');
    const orig = btn.textContent;
    btn.textContent = 'Отправляем…';
    btn.disabled = true;
    setTimeout(() => {
      form.reset();
      btn.textContent = orig;
      btn.disabled = false;
      openModal(`
        <div class="modal__success-icon">
          <span class="material-symbols-outlined">check_circle</span>
        </div>
        <h2 style="font-size:1.6rem; margin:0 0 .75rem;">Заявка принята</h2>
        <p class="text-mut" style="font-size:1rem; line-height:1.6; margin:0 0 1.5rem;">
          Спасибо! Менеджер MEYOS свяжется с вами в течение одного рабочего дня.
        </p>
        <button class="btn btn-primary" data-modal-close>Хорошо</button>
      `, { success: true });
      const closeBtn = document.querySelector('#meyos-modal [data-modal-close]');
      if (closeBtn) closeBtn.addEventListener('click', closeModal);
    }, 900);
  });
}
function init() {
  initMobileMenu();
  initLang();
  initForms();
  initPartnersFilter();
  initNewsFilter();
  initNewsPopup();
  initDeadLinks();
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}